var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"하아…… 하아……","ENG":"Haa... haa..."},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR","hologram":false},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INO_COLLABO_NULL_NULL","text":{"KOREA":"으흐음, 시시껄렁한 불꽃놀이들과는 비교도 안 되게 멋진 리허설이었어.","ENG":"Mmm, that was a magnificent rehearsal—incomparable to those petty fireworks."},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INO_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"아……! 제, 제가 또 정신 없이 싸웠나요?","ENG":"Ah...! D-did I lose myself in the fight again?"},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_SURPRISE","hologram":false},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"죄송해요. 총을 오래 쏘다 보면 가끔 정신이 멍해질 때가 있어서……","ENG":"I'm sorry. When I shoot for too long, my mind sometimes goes blank..."},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR","hologram":false},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INO_COLLABO_NULL_NULL","text":{"KOREA":"아니. 오히려 마음에 쏙 들었어. 댄스 파티라도 열리는 줄 알았지 뭐야.","ENG":"Not at all. I rather enjoyed it. I thought a dance party was breaking out."},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"INO_COLLABO_NULL_NULL","face":"UNIT_LAUGH","hologram":false}}}},{"id":"L10_1","type":"dialog","speaker":"INO_COLLABO_NULL_NULL","text":{"KOREA":"공연에 소질 있더라, 귀여운 아가씨?","ENG":"You've got a talent for the stage, don't you, cutie?"},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"INO_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L11_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"그, 그랬나요……?","ENG":"R-really...?"},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"INO_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L12_1","type":"dialog","speaker":"INO_COLLABO_NULL_NULL","text":{"KOREA":"그럼. 기관포로 그렇게 피가 끓어오를 만큼 뜨거운 연주를 할 줄 아는 사람은 흔치 않아.","ENG":"Of course. It's rare to find someone who can deliver a performance so fiery it makes blood boil, using a machine gun."},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"INO_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L13_1","type":"dialog","speaker":"INO_COLLABO_NULL_NULL","text":{"KOREA":"조금 더 듣고 싶은 욕심도 나는데, 날 위해 한 번 더 들려 줄래?","ENG":"I'm tempted to hear more. Won't you play it again for me?"},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"INO_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L14_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"저…… 정말요?","ENG":"I... really?"},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_IDLE","hologram":false},"C":null,"R":{"char_id":"INO_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L15_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"전 그동안 너무 요란하게 싸워서…… 다른 애들한테 민폐 같았거든요.","ENG":"I've been fighting so chaotically... I felt like I was just a burden to the others."},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR","hologram":false},"C":null,"R":{"char_id":"INO_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L16_1","type":"dialog","speaker":"INO_COLLABO_NULL_NULL","text":{"KOREA":"흐응, 앵콜도 안 외치고 네 진가를 몰라보는 녀석들이네. 목이 터지게 환호해도 시원치 않을 판에.","ENG":"Hmph, not even calling for an encore? They fail to see your true worth. They should be cheering their lungs out."},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR","hologram":false},"C":null,"R":{"char_id":"INO_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L17_1","type":"dialog","speaker":"INO_COLLABO_NULL_NULL","text":{"KOREA":"운이 좋은 애구나, 너.","ENG":"You're a lucky one."},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR","hologram":false},"C":null,"R":{"char_id":"INO_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L18_1","type":"dialog","speaker":"INO_COLLABO_NULL_NULL","text":{"KOREA":"나랑 안 만났으면 그 쓰레기들 사이에서 패배자 인생을 살았을 텐데.","ENG":"If you hadn't met me, you'd have lived a loser's life among that trash."},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR","hologram":false},"C":null,"R":{"char_id":"INO_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false}}}},{"id":"L20_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"아, 아니에요. 윤이도, 유진이도, 린도 소중한 동료들인 걸요……","ENG":"N-no. Yuni, Eujin, and Lin are all precious comrades..."},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR","hologram":false},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"INO_COLLABO_NULL_NULL","text":{"KOREA":"저런, 착한 아이 같은 개소리는 때려치워.","ENG":"Oh please, quit that goody-two-shoes nonsense."},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INO_COLLABO_NULL_NULL","face":"UNIT_LAUGH","hologram":false},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"INO_COLLABO_NULL_NULL","text":{"KOREA":"너는 누구보다 화려하게 폭발하는 모습이 어울려. 평생 쓰레기들 수발이나 들면서 살 셈이야?","ENG":"You're meant to explode in splendor, more than anyone else. You intend to live your life serving those losers?"},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INO_COLLABO_NULL_NULL","face":"UNIT_HATE","hologram":false},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"그, 그렇지는 않은데……","ENG":"Th-that's not..."},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR","hologram":false},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INO_COLLABO_NULL_NULL","text":{"KOREA":"얼버무릴 필요 없어. 내가 지금부터 천천히 가르쳐 줄게.","ENG":"No need to play dumb. I'll teach you slowly, starting now."},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INO_COLLABO_NULL_NULL","face":"UNIT_IDLE","hologram":false},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INO_COLLABO_NULL_NULL","text":{"KOREA":"지금부터 너 자신에게…… 아주 솔직해지는 거야.","ENG":"Starting now... you're going to be completely honest with yourself."},"stage":{"bg":"PARK_DESTROYED","bgm":"GUILTY_106","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};